mapper.select:
SELECT COUNT(*)
FROM CAREER_DIAGNOSIS
WHERE USER_ID = #{userId}

SELECT MAX(DIAGNOSIS_ID)
FROM CAREER_DIAGNOSIS
WHERE USER_ID = #{userId}

mapper.insert:
INSERT INTO CAREER_TARGET_SKILL (
    TARGET_SKILL_ID,
    DIAGNOSIS_ID,
    SKILL_ID
) VALUES (
    CAREER_TARGET_SKILL_SEQ.NEXTVAL,
    #{diagnosisId},
    #{skillId}
)

mapper.select:
SELECT COUNT(*)
FROM LEVEL_TEST_QUESTION
WHERE DIAGNOSIS_ID = #{diagnosisId}

SELECT COUNT(*)
FROM CAREER_RECOMMENDATION
WHERE DIAGNOSIS_ID = #{diagnosisId}

SELECT COUNT(*)
FROM CAREER_TARGET_SKILL
WHERE DIAGNOSIS_ID = #{diagnosisId}

mapper.update:
UPDATE CAREER_DIAGNOSIS
SET LEVEL_TEST_BUILD_STATUS = #{status}
WHERE DIAGNOSIS_ID = #{diagnosisId}

UPDATE CAREER_DIAGNOSIS
SET LLM_SUMMARY = #{llmSummary, jdbcType=CLOB}
WHERE DIAGNOSIS_ID = #{diagnosisId}

mapper.select:
SELECT SKILL_ID AS skillId, '중' AS difficulty
FROM CAREER_TARGET_SKILL
WHERE DIAGNOSIS_ID = #{diagnosisId}
